import React, { useRef, useState, useEffect, useCallback } from "react";
const useProgressQueue = (duration = 3000) => {
    const [queue, setQueue] = useState([]); // Stores progress values: [100, 100, 45, 0]
    const [activeIdx, setActiveIdx] = useState(0);

    const requestRef = useRef();
    const startTimeRef = useRef();

    const addBar = useCallback(() => {
        setQueue((prev) => [...prev, 0]);
    }, []);

    const animate = useCallback((time) => {
        if (!startTimeRef.current) startTimeRef.current = time;

        const elapsed = time - startTimeRef.current;
        const progress = Math.min((elapsed / duration) * 100, 100);

        setQueue((prev) => {
            const updated = [...prev];
            updated[activeIdx] = progress;
            return updated;
        });

        if (progress < 100) {
            requestRef.current = requestAnimationFrame(animate);
        } else {
            cancelAnimationFrame(requestRef.current);
            startTimeRef.current = null;
            setActiveIdx((prev) => prev + 1);
        }
    }, [activeIdx, duration]);

    useEffect(() => {
        if (activeIdx < queue.length) {
            requestRef.current = requestAnimationFrame(animate);
        }
        return () => cancelAnimationFrame(requestRef.current);
    }, [activeIdx, queue.length, animate]);

    return { queue, addBar };
};

export default useProgressQueue
